  title: "Resume",
  description: summary,
};

type SearchParams = Promise<{ print?: string }>;

export default async function ResumePage({
  searchParams,
}: {
  searchParams?: SearchParams;
}) {
  const params = (await searchParams) ?? {};
  const isPrint = params.print === "true";

  return (
    <>
      {isPrint && <PrintMode />}
      <Container
        as="main"
        size="base"
        style={{ paddingTop: "var(--s-7)", paddingBottom: "var(--s-9)" }}
      >
        <Stack gap={7}>
          <ResumeIdentity
            name={identity.name}
            role={identity.role}
            email={identity.email}
            location={identity.location}
            links={identity.links}
          />
          <ResumeSummary text={summary} />
          <ResumeTimeline heading="experience" items={experience} />
          <ResumeSkills groups={skills} />
          <ResumeTimeline heading="education" items={education} />
          {writing.length > 0 && <ResumeWriting items={writing} />}
          <DownloadCTA />
        </Stack>
      </Container>
    </>
  );
}
